// GetFromRegistry decrypts a value from the registry if it exists.
func GetFromRegistry(key string, masterKey string) []string {
	encrypted, exists := InternalRegistry[key]
	if !exists || encrypted == "" {
		return nil
	}

	decrypted, err := security.Decrypt(encrypted, masterKey)
	if err != nil {
		log.Printf("⚠️ Failed to decrypt internal registry key %s: %v", key, err)
		return nil
	}

	return getSliceFromText(decrypted, ",")
}

func getSliceFromText(val string, sep string) []string {
	if val == "" {
		return []string{}
	}
	// Note: We'll use a local version of getEnvAsSlice logic if needed,
	// but for now, we'll just implement a simple version here or reuse logic.
	return []string{val} // Simplified for now, will handle comma-separation in the tool
}
